import osimport utils_study study = utils_study.Studyutils = utils_study.Utils()import utils_preprocessing_analysispreprocess_analyse = utils_preprocessing_analysis.OPM_Pipeline(incl_report=False)# =============================================================================# Parameters # =============================================================================input_folder = 'processed_filtered'output_folder = 'preprocessing_routine_3'task = 'oddballTones'# Inser the path to your project folder# root_data_path = '/Users/a.pesquita@bham.ac.uk/Documents/GitHub/babypyopm/Untitled'root_data_path = '/Users/b.pomiechowska@bham.ac.uk/Documents/GitHub/babypyopm/'# =============================================================================# Set up # =============================================================================# Get paths to all subfolderspaths = utils.get_paths(root_data_path)# Define the template for generating the filename for raw FIF data filesbasename = '{subj}/{input_folder}/{sub-subj}_file-{task}_filtered_01_40.fif'# Find FIF files that correspond to the template defined abovedataset = study(os.path.join(paths.data, basename)) # List all folders / subjects in '~/data'subjects = [f for f in os.listdir(paths.data) if os.path.isdir(os.path.join(paths.data, f))]print(subjects)subjects = ['sub-107']#%% ----------------------------------------------# Load datasetsdata = preprocess_analyse.load_data(dataset, subjects,paths.data,input_folder,task)ica_data = [preprocess_analyse.run_ICA(d, output_folder, paths.results, False) for d in data]# Save fif files with event info[utils.save_fif_path(d, task, output_folder, paths.data, output_folder) for d in ica_data]